#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 1000000007LL;

int64_t modPow(int64_t base, int64_t exp) {
    int64_t res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        int64_t pow2N = modPow(2, N);
        int64_t a = (pow2N - 1 + MOD) % MOD;
        int64_t ans = modPow(a, M);
        printf("%lld\n", ans);
    }
    return 0;
}

