#!/usr/bin/env python3
import sys
MOD = 1000000007

def mod_pow(base, exp):
    return pow(base, exp, MOD)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        M = int(next(it))
        pow2N = mod_pow(2, N)
        a = (pow2N - 1) % MOD
        ans = mod_pow(a, M)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

